INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 19814085, 0, 21, 19814, "vo_wac_19814_003", "vo_wac_19814", 0, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 19814086, 10, 11, 19814, "誕生日にそんなことされて喜ぶのは、\nクウカさんだけだと思います……", 105511, 1, 0.5, 1);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 19814087, "", 91, 19814, "", 0, "", "", "");
