INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 25214060, 0, 21, 25214, "vo_wac_25214_001", "vo_wac_25214", 0, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 25214061, 10, 11, 25214, "ちょっと待ってくださいお姉ちゃん！\n私たちも手伝ってますよ！\nココとか！　ココもです！", 101111, 1, 0.5, 1);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 25214062, "", 91, 25214, "", 0, "", "", "");
