INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 25214066, 10, 11, 25214, "シズルちゃんへの感謝の\n気持ちを込めてね。\nって、お邪魔じゃなければ\nいいんだけど。", 106811, 1, 0.5, 1);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 25214067, "", 91, 25214, "", 0, "", "", "");
