INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 25214071, 10, 11, 25214, "そんなことないよ～。\nありがとうね、マスター、リノちゃん。\n弟くんにはこのあとたっぷりと\n付き合ってもらうから大丈夫だよ。ね？", 104911, 1, 0.5, 1);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 25214072, "", 91, 25214, "", 0, "", "", "");
