INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 26224078, 10, 11, 26224, "おめでとう、カスミ！\nていうか、姫さんほんとに踊るのか？\nだったら、カスミも一緒に踊ろうぜ！\nみんなでやった方が楽しいからな♪", 104311, 1, 0.5, 1);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 26224079, "", 91, 26224, "", 0, "", "", "");
