INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 28414063, 10, 11, 28414, "わわっ、大きなケーキッス！\n……え、もしかして自分のッスかねっ？\n誕生日覚えてくれてたッスか？", 100511, 1, 0.5, 1);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 28414064, "", 91, 28414, "", 0, "", "", "");
