INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 34314091, 10, 11, 34314, "でも、喜んでもらえてなによりです。\nミヤコさんが明るく振る舞う限り、\n穢れのない魂のまま、\n悪霊に転じることもないでしょう……", 103111, 1, 0.5, 1);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 34314092, "", 91, 34314, "", 0, "", "", "");
