INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 34414063, 10, 11, 34414, "楽しそうではありますが……\nよく考えたら、お祝いされる方が\n歌って踊るというのも\n不思議な話ではありますね。", 104211, 1, 0.5, 1);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 34414064, "", 91, 34414, "", 0, "", "", "");
